// 019: Read hook token from Static Data (not $env)
const staticData = $getWorkflowStaticData('global');
const hookToken = staticData.hookToken || '';

// Extract error details from the failed workflow execution
const errorData = $input.all()[0].json;

const workflowName = errorData.workflow?.name || 'unknown';
const executionId = errorData.execution?.id || 'unknown';
const errorMessage = errorData.execution?.error?.message || 'Unknown error';
const errorNode = errorData.execution?.error?.node?.name || 'unknown node';

// Classify error for the alert
let errorCode = 'workflow_error';
let severity = 'error';

if (errorMessage.includes('401') || errorMessage.includes('Unauthorized')) {
  errorCode = 'token_expired';
} else if (errorMessage.includes('429') || errorMessage.includes('rate limit')) {
  errorCode = 'rate_limited';
  severity = 'warning';
} else if (errorMessage.includes('403') || errorMessage.includes('Forbidden')) {
  errorCode = 'account_restricted';
}

return [{
  json: {
    type: 'alert',
    alert_type: 'workflow_failure',
    message: `${workflowName} workflow failed: ${errorMessage}`,
    severity: severity,
    workflow_name: workflowName,
    execution_id: executionId,
    error_code: errorCode,
    error_details: `${errorMessage} (at node: ${errorNode})`,
    affected_content: errorData.execution?.data?.resultData?.lastNodeExecuted || 'unknown'
  }
}];
